exercises.solution_code:
#include <iostream>

constexpr int PI_SCALED = 314;
constexpr int RADIUS = 5;

consteval int scaled_area(int r) {
    return PI_SCALED * r * r;
}

consteval int scaled_circumference(int r) {
    return 2 * PI_SCALED * r;
}

int main() {
    constexpr int area_num = scaled_area(RADIUS);
    constexpr int circ_num = scaled_circumference(RADIUS);

    static_assert(area_num == 7850);
    static_assert(circ_num == 3140);

    std::cout << "Radius: " << RADIUS << "\n";
    std::cout << "Area numerator: " << area_num << "\n";
    std::cout << "Circumference numerator: " << circ_num << "\n";
    return 0;
}
